1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Customer = { yearsWithMHPCO: number };
4	type Scenario = { customer: Customer; steps: QuoteStep[] };
5	type QuoteResult = { premium: number };
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_RATE = 0.1;
9	
10	const ITEM_BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const BLOCK_SIZE = 3;
20	const BLOCK_BASE_PREMIUM = 60;
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const CURSE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_RATE = 0.3;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	const LOYALTY_RATE = 0.2;
27	const LOYALTY_THRESHOLD_YEARS = 2;
28	const FOLLOW_UP_RATE = 0.15;
29	
30	const sumBy = <T>(items: T[], f: (x: T) => number): number =>
31	  items.reduce((acc, x) => acc + f(x), 0);
32	
33	const baseFor = (item: Item): number => ITEM_BASE_PREMIUMS[item.type];
34	
35	const SURCHARGE_RULES: ReadonlyArray<{ applies: (item: Item) => boolean; rate: number }> = [
36	  { applies: (item) => item.cursed === true, rate: CURSE_RATE },
37	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_RATE },
38	];
39	
40	const surchargeFor = (item: Item): number => {
41	  const base = baseFor(item);
42	  return sumBy(SURCHARGE_RULES, (rule) => (rule.applies(item) ? base * rule.rate : 0));
43	};
44	
45	const totalSurchargeFor = (items: Item[]): number => sumBy(items, surchargeFor);
46	
47	const loyaltyDiscountFor = (customer: Customer, totalBase: number): number =>
48	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? totalBase * LOYALTY_RATE : 0;
49	
50	const premiumFor = (totalBase: number, totalSurcharge: number, customer: Customer, isFollowUp: boolean): number =>
51	  totalBase
52	  + totalSurcharge
53	  + Math.ceil(totalBase * FIRST_INSURANCE_RATE)
54	  - loyaltyDiscountFor(customer, totalBase)
55	  - (isFollowUp ? totalBase * FOLLOW_UP_RATE : 0)
56	  + PROCESSING_FEE;
57	
58	const groupByType = (items: Item[]): Map<string, Item[]> => {
59	  const groups = new Map<string, Item[]>();
60	  for (const item of items) {
61	    const group = groups.get(item.type) ?? [];
62	    group.push(item);
63	    groups.set(item.type, group);
64	  }
65	  return groups;
66	};
67	
68	const formsCompleteBlock = (group: Item[]): boolean =>
69	  group.length === BLOCK_SIZE && COMPONENT_TYPES.has(group[0].type);
70	
71	const baseForGroup = (group: Item[]): number =>
72	  formsCompleteBlock(group) ? BLOCK_BASE_PREMIUM : sumBy(group, baseFor);
73	
74	const totalBaseFor = (items: Item[]): number =>
75	  sumBy(Array.from(groupByType(items).values()), baseForGroup);
76	
77	const quoteFor = ({ items }: QuoteStep, customer: Customer, isFollowUp: boolean): QuoteResult => ({
78	  premium: premiumFor(totalBaseFor(items), totalSurchargeFor(items), customer, isFollowUp),
79	});
80	
81	export const processScenario = (input: Scenario): { results: QuoteResult[] } => {
82	  let quoteCount = 0;
83	  const results = input.steps.map((step) => {
84	    const isFollowUp = quoteCount > 0;
85	    quoteCount += 1;
86	    return quoteFor(step, input.customer, isFollowUp);
87	  });
88	  return { results };
89	};
